var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"…그렇지. 그녀와 난… 늘 저 언덕에서 함께 경치를 바라보곤 했어.","JPN":"……ああ。彼女と私は……あの丘でよく一緒に景色を眺めていた。","ENG":"…Yes. She and I… used to sit on that hill, taking in the view together.","TWN":"…沒錯。我和她…總是在那座山坡上一起眺望風景。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"이 드넓은 황무지가… 사람들이 지어 올린 꿈으로 가득 차는 풍경을 그리면서 말이야.","JPN":"この広大な荒地が……人々が築き上げた夢で埋め尽くされる姿を思い描いて。","ENG":"We'd picture this barren land… blooming with dreams people had built.","TWN":"一邊想像著，這片廣闊的荒地…總有一天會被人們用夢想填滿。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"회장님! 여긴 침식지대의 중심입니다! 어서 빠져나가셔야 해요!","JPN":"会長！　ここは侵食地帯の中心です！　早くお逃げください！","ENG":"President! This is the heart of the Corrupted Area! We need to get out of here!","TWN":"會長！這裡是侵蝕地帶的中心！你必須趕快離開！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"자넨 저게 보이지 않는 건가? 우리의 그리운 옛 시절이.","JPN":"君にはあれが見えないのか？　我々の懐かしき頃の姿が。","ENG":"Don't you see it? The past we cherished.","TWN":"你看不見嗎？我們懷念的舊時光。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"그건 침식파가 만들어낸 환상일 뿐입니다.","JPN":"それは侵食波が作り出した幻です。","ENG":"It's nothing but an illusion created by Corruption rays!","TWN":"那只是侵蝕波製造出來的幻覺。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"서둘러 나가지 않으면 잠식되고 말아요!","JPN":"早く抜け出さないと呑み込まれてしまいます！","ENG":"If we don't get out, we'll be corrupted!","TWN":"再不趕快離開，你就會被侵蝕！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_14","text":{"KOREA":"실패입니다! 알 수 없는 방해 전파 때문에 외부와 통신이 전혀 되지 않아요!","JPN":"ダメです！　謎の妨害電波のせいで外との通信がまったく繋がりません！","ENG":"We've lost all comms! Some kind of interference is jamming every signal!","TWN":"失敗了！因為不明的干擾電波，無法與外界通訊！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"이건… 평범한 사람이 거스를 수 있는 현상이 아닌 거야.","JPN":"これは……普通の人間が逆らえる現象ではないのだよ。","ENG":"This… isn't something ordinary people can resist.","TWN":"這不是…普通人能抗衡的現象。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"그러니 구원을 기다리거나, 순순히 받아들이는 수 밖에.","JPN":"だから救いを待つか、従順に受け入れるしかない。","ENG":"So either we wait for salvation or accept the end.","TWN":"所以，除了等待救援，就只能順從地接受。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"포기하시면 안 됩니다. 저희가 어떻게든 벗어날 방도를…","JPN":"諦めてはいけません。私たちがなんとかして逃げる方法を……","ENG":"Please don't give up. There must be a way out–","TWN":"不能放棄！我們會想辦法讓你離開…"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"이런, 침식체까지?!","JPN":"そんな、侵食体まで！？","ENG":"Damn, C.O.s?!","TWN":"什麼，連侵蝕體都來了？！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_14","text":{"KOREA":"이놈들… 정말 빠릅니다. 완전히 둘러싸였어요.","JPN":"こいつら……尋常じゃない速さです。完全に包囲されました。","ENG":"They're fast… Way too fast! We're surrounded.","TWN":"這些傢伙…真的好快。我們完全被包圍了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"어떻게든 길을 뚫어. 회장님을 대피시킬 수 있도록…!","JPN":"どうにかして道を開けるんだ。会長が避難できるように……！","ENG":"Push through somehow! We have to get the President out of here…!","TWN":"想辦法開出一條路。讓我們能護送會長…！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"이쪽이로군.","JPN":"こちらか。","ENG":"This way.","TWN":"是這邊。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"사람인가?","JPN":"人か？","ENG":"Is that a person?","TWN":"是人嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_14","text":{"KOREA":"카운터다! 이제 살았어요!","JPN":"カウンターだ！　これで助かりました！","ENG":"It's a Counter! We're saved!","TWN":"是制裁者！我們得救了！"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"자넨…? 여길 어떻게 들어왔지?","JPN":"君は……？　どうやってここへ入って来た？","ENG":"You're…? How did you get in here?","TWN":"你是…？你是怎麼進來的？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OLDMAN_NPC_ALPHA_14","text":{"KOREA":"시간을 거슬러 과거를 보여줄 정도의 왜곡성 침식이라면… 제아무리 카운터라도 쉽게 뚫고 들어올 수 없을 텐데.","JPN":"時を遡り過去を見せるほどの歪曲性侵食は……いくらカウンターでも簡単に潜り抜けないはず。","ENG":"With this much warping Corruption enough to bend time and pull in the past… It should've been impossible for even a Counter to breach.","TWN":"若是能逆轉時間、展現過去的那種扭曲性侵蝕…就算是再怎麼厲害的制裁者，也絕非能輕易突破的吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 이유를 다 설명하려면 얘기가 늘어질 거요.","JPN":"全部説明すると長くなるのでな。","ENG":"If I tried to explain, we'd be here all day.","TWN":"如果要解釋原因，話就說來長了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우선 여길 벗어나는 것부터 시작하지.","JPN":"ここを離れることのほうが先だ。","ENG":"Let's get out of here first.","TWN":"先離開這裡吧。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_14","text":{"KOREA":"신원이 어떻게 되지? 관리국에서 보낸 사람인가?","JPN":"身元は？　管理局が送った者か？","ENG":"What's your affiliation? Did the Administration send you?","TWN":"請問你的身分是？是管理局派來的人嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"관리국 직원은 아닐세. 와류흔 내부에 사람이 갇혀 있다고 엿듣게 되어서 말이지.","JPN":"管理局の職員ではない。渦流痕のどこかに人が閉じ込められているという話を聞きつけたのでな。","ENG":"I'm not an official employee. I just overheard someone was trapped in the Vortex Scar.","TWN":"我不是管理局的員工。我只是偶然聽到有人被困在渦流痕裡。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GUARD_NPC_ALPHA_14","text":{"KOREA":"침식체들이 계속 몰려들고 있어. 돌파할 수 있겠나?","JPN":"侵食体が絶え間なく押し寄せてきているが、突破できるのか？","ENG":"The C.O.s keep coming. Can you get us out?","TWN":"侵蝕體一直在湧過來。能突破嗎？"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"앞장설 테니, 뒤쳐지지 마시게.","JPN":"某が先頭に立つ。遅れずついて来たまえ。","ENG":"I'll lead. Don't fall behind.","TWN":"我會開路，別落後了。"},"stage":{"bg":"SUMMER_CLIFF","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_NPC_ALPHA_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_NPC_ALPHA_14","face":"UNIT_IDLE"}}}}]`);export{e as default};